  .replace(/<a\b[^>]*>(.*?)<\/a>/gi, '')
  .replace(/\[image:[^\]]*\]/gi, '')
  .replace(/<https?:\/\/[^>]*>/gi, '');

return {
  json: {
    id: item.json.id,
    from: item.json.from.text,
    to: item.json.to.text,
    subject: item.json.subject,
    text: cleanedText
  }
}

